const rows = $input.all().filter(i => i.json && i.json.id !== undefined && i.json.id !== null);
return [{ json: {
  pending: rows.length > 0,
  pending_id: rows.length ? rows[0].json.id : null,
  pending_language: rows.length ? rows[0].json.language : 'hi',
} }];

// ---- PENDING BRANCH: this message is treated as the location answer ----
const trig = $('Execute Workflow Trigger').first().json;
const wards = $('Fetch Wards').all().map(i => i.json);
const flag = $('Pending Flag').first().json;

function pointInRing(pt, ring) {
  let inside = false;
  for (let i = 0, j = ring.length - 1; i < ring.length; j = i++) {
    const xi = ring[i][0], yi = ring[i][1];
    const xj = ring[j][0], yj = ring[j][1];
    const intersect = ((yi > pt[1]) !== (yj > pt[1])) && (pt[0] < (xj - xi) * (pt[1] - yi) / (yj - yi) + xi);
    if (intersect) inside = !inside;
  }
  return inside;
}
function pointInGeom(pt, geom) {
  if (!geom) return false;
  try {
    if (geom.type === 'Polygon') return pointInRing(pt, geom.coordinates[0]);
    if (geom.type === 'MultiPolygon') return geom.coordinates.some(poly => pointInRing(pt, poly[0]));
  } catch (e) { return false; }
  return false;
}

let ward_id = null, ward_resolution = 'manual_review';
const lat = parseFloat(trig.lat), lng = parseFloat(trig.lng);
if (!isNaN(lat) && !isNaN(lng)) {
  const m = wards.find(w => pointInGeom([lng, lat], w.geom));
  if (m) { ward_id = m.id; ward_resolution = 'gps'; }
}
if (!ward_id && trig.text) {
  const guess = String(trig.text).toLowerCase().trim();
  const m = wards.find(w =>
    w.name.toLowerCase() === guess ||
    guess.includes(w.name.toLowerCase()) ||
    (w.aliases || []).some(a => guess.includes(a.toLowerCase()) || a.toLowerCase().includes(guess))
  );
  if (m) { ward_id = m.id; ward_resolution = 'alias_match'; }
}

return [{ json: {
  submission_id: flag.pending_id,
  ward_id, ward_resolution,
  location_text: trig.text || trig.location_text || null,
  language: flag.pending_language || 'hi',
} }];

const r = $('Resolve Ward From Reply').first().json;
const hi = (r.language || 'hi').startsWith('hi');
const ok = r.ward_resolution !== 'manual_review';
const ack = ok
  ? (hi ? 'Dhanyavaad! Aapki jagah darj ho gayi ✅ Jab is par kaam hoga, aapko update milega.' : 'Thank you! Your location has been recorded ✅ You will get an update when there is progress.')
  : (hi ? 'Dhanyavaad! Humne aapka jawab note kar liya hai — hamari team jagah confirm karegi.' : 'Thank you! We have noted your reply — our team will confirm the exact area.');
return [{ json: {
  submission_id: r.submission_id,
  ack_text: ack,
  followup_text: '',
  ward_resolution: r.ward_resolution,
  category: null,
  ask: null,
  mode: 'ward_update',
} }];

// ---- NEW SUBMISSION BRANCH ----
const trig = $('Execute Workflow Trigger').first().json;
const wards = $('Fetch Wards').all().map(i => i.json);
const wardList = wards.map(w => `${w.name}${(w.aliases && w.aliases.length) ? ' (aka: ' + w.aliases.join(', ') + ')' : ''}`).join('; ');
const hasGps = trig.lat !== null && trig.lat !== undefined && trig.lat !== '' && !isNaN(parseFloat(trig.lat));

const parts = [];
if (trig.media_type === 'voice' && trig.audio_base64) {
  parts.push({ inline_data: { mime_type: trig.mime_type || 'audio/ogg', data: trig.audio_base64 } });
} else if (trig.media_type === 'photo' && trig.photo_base64) {
  parts.push({ inline_data: { mime_type: trig.mime_type || 'image/jpeg', data: trig.photo_base64 } });
}

const promptText = `You process a citizen's message about a local development need in an Indian constituency (categories: education, water, roads, health, electricity, sanitation, other). The input may include audio, an image, and/or the text below.

Citizen text (may be empty if audio/image only): ${trig.text || '(none — see attached media)'}
Citizen-shared location text (may be empty): ${trig.location_text || '(none)'}
GPS coordinates provided: ${hasGps ? 'yes' : 'no'}

Output ONLY strict JSON, no markdown, matching exactly this shape:
{
  "transcript": string or null,
  "media_description": string or null,
  "ask": string,
  "category": "education|water|roads|health|electricity|sanitation|other",
  "sub_type": string,
  "urgency_signals": [string],
  "language": string,
  "ward_guess": string or null,
  "ack_text": string,
  "location_followup": string
}

Field rules:
- transcript: verbatim transcription if audio was given, else null.
- media_description: factual description if an image was given, else null.
- ask: one-line summary in English of what the citizen needs.
- sub_type: short snake_case tag, e.g. infrastructure_repair, tap_connection, road_repair.
- urgency_signals: ONLY signals explicitly present, e.g. ["monsoon","children_affected"]. [] if none.
- language: ISO code of the language the citizen used, e.g. "hi", "en".
- ward_guess: EXACT copy of one name from the ward list below, or null if unsure. NEVER invent a name.
- ack_text: 1-2 warm sentences IN THE CITIZEN'S LANGUAGE confirming what was understood and that they'll get an update. NEVER promise the work will be done.
- location_followup: one short question IN THE CITIZEN'S LANGUAGE asking which ward/area/mohalla they live in (always generate this; it is only sent if we cannot locate them).

Ward list (pick ward_guess ONLY from these names, exactly as written): ${wardList}

Rules: use null for anything absent or uncertain. Never guess urgency, category, or ward if not clearly indicated by the citizen.`;

parts.push({ text: promptText });

return [{ json: {
  gemini_body: {
    contents: [{ parts }],
    generationConfig: { responseMimeType: 'application/json', maxOutputTokens: 2000 }
  }
} }];

const trig = $('Execute Workflow Trigger').first().json;
const wards = $('Fetch Wards').all().map(i => i.json);

let extracted = {};
try {
  const raw = $json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  extracted = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch (e) {
  extracted = {};
}
const lang = extracted.language || trig.language_hint || 'hi';
const hi = String(lang).startsWith('hi');
if (!extracted.ask) {
  extracted = {
    ...extracted,
    ask: trig.text || 'unspecified need',
    category: extracted.category || 'other',
    sub_type: extracted.sub_type || 'unspecified',
    urgency_signals: extracted.urgency_signals || [],
    language: lang,
    ward_guess: extracted.ward_guess || null,
    ack_text: extracted.ack_text || (hi ? 'Aapki baat mil gayi, dhanyavaad. Hum jaldi update denge.' : 'We received your message, thank you. We will update you soon.'),
  };
}
if (!extracted.location_followup) {
  extracted.location_followup = hi ? 'Aap kis ward ya ilaake mein rehte hain?' : 'Which ward or area do you live in?';
}

function pointInRing(pt, ring) {
  let inside = false;
  for (let i = 0, j = ring.length - 1; i < ring.length; j = i++) {
    const xi = ring[i][0], yi = ring[i][1];
    const xj = ring[j][0], yj = ring[j][1];
    const intersect = ((yi > pt[1]) !== (yj > pt[1])) && (pt[0] < (xj - xi) * (pt[1] - yi) / (yj - yi) + xi);
    if (intersect) inside = !inside;
  }
  return inside;
}
function pointInGeom(pt, geom) {
  if (!geom) return false;
  try {
    if (geom.type === 'Polygon') return pointInRing(pt, geom.coordinates[0]);
    if (geom.type === 'MultiPolygon') return geom.coordinates.some(poly => pointInRing(pt, poly[0]));
  } catch (e) { return false; }
  return false;
}

let ward_id = null, ward_resolution = 'pending';
const lat = parseFloat(trig.lat), lng = parseFloat(trig.lng);
if (!isNaN(lat) && !isNaN(lng)) {
  const match = wards.find(w => pointInGeom([lng, lat], w.geom));
  if (match) { ward_id = match.id; ward_resolution = 'gps'; }
}
if (!ward_id && extracted.ward_guess) {
  const guess = String(extracted.ward_guess).toLowerCase().trim();
  const match = wards.find(w =>
    w.name.toLowerCase() === guess ||
    (w.aliases || []).some(a => a.toLowerCase() === guess)
  );
  if (match) { ward_id = match.id; ward_resolution = 'alias_match'; }
}

return [{ json: {
  channel: trig.channel,
  citizen_key: trig.citizen_key,
  media_type: trig.media_type,
  text: trig.text,
  transcript: extracted.transcript || null,
  media_description: extracted.media_description || null,
  ask: extracted.ask,
  category: extracted.category,
  sub_type: extracted.sub_type,
  urgency_signals: extracted.urgency_signals || [],
  language: extracted.language || lang,
  lat: trig.lat, lng: trig.lng, location_text: trig.location_text,
  ward_id, ward_resolution,
  ack_text: extracted.ack_text,
  followup_text: extracted.location_followup,
} }];

const src = $('Parse & Resolve Ward').first().json;
const trig = $('Execute Workflow Trigger').first().json;
const b64 = src.media_type === 'voice' ? trig.audio_base64 : trig.photo_base64;
const mime = trig.mime_type || (src.media_type === 'voice' ? 'audio/ogg' : 'image/jpeg');
const ext = (mime.split('/')[1] || 'bin').split(';')[0];
const fileName = `${src.channel}-${Date.now()}.${ext}`;
const buffer = Buffer.from(b64, 'base64');
const binaryData = await this.helpers.prepareBinaryData(buffer, fileName, mime);
return [{ json: { media_filename: fileName, media_mime: mime }, binary: { data: binaryData } }];

const filename = $('Prepare Binary').first().json.media_filename;
const url = `https://YOUR_SUPABASE_PROJECT_REF.supabase.co/storage/v1/object/public/media/${filename}`;
return [{ json: { media_ref: url } }];

const parsed = $('Parse & Resolve Ward').first().json;
const submissionId = $('Insert Submission').first().json.id;
return [{ json: {
  submission_id: submissionId,
  ack_text: parsed.ack_text,
  followup_text: parsed.ward_resolution === 'pending' ? parsed.followup_text : '',
  ward_resolution: parsed.ward_resolution,
  category: parsed.category,
  ask: parsed.ask,
  mode: 'new',
} }];
